from datetime import datetime, timedelta, timezone
from functools import wraps
import os

from flask import Flask, request, jsonify, g
import jwt
from werkzeug.security import generate_password_hash, check_password_hash

app = Flask(__name__)

app.config["SECRET_KEY"] = os.getenv("SECRET_KEY", "change-this-secret")
app.config["JWT_ALGORITHM"] = "HS256"
app.config["JWT_EXPIRATION_MINUTES"] = int(os.getenv("JWT_EXPIRATION_MINUTES", "60"))

users = {
    "admin": {
        "id": 1,
        "username": "admin",
        "password_hash": generate_password_hash("admin123"),
    }
}

def create_token(user_id, username):
    now = datetime.now(timezone.utc)
    payload = {
        "sub": str(user_id),
        "username": username,
        "iat": now,
        "exp": now + timedelta(minutes=app.config["JWT_EXPIRATION_MINUTES"]),
    }
    return jwt.encode(payload, app.config["SECRET_KEY"], algorithm=app.config["JWT_ALGORITHM"])

def decode_token(token):
    return jwt.decode(token, app.config["SECRET_KEY"], algorithms=[app.config["JWT_ALGORITHM"]])

def token_required(fn):
    @wraps(fn)
    def wrapper(*args, **kwargs):
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            return jsonify({"error": "Authorization header must be in the format: Bearer <token>"}), 401

        token = auth_header.split(" ", 1)[1].strip()
        if not token:
            return jsonify({"error": "Token is missing"}), 401

        try:
            payload = decode_token(token)
            g.current_user = {
                "id": int(payload["sub"]),
                "username": payload["username"],
            }
        except jwt.ExpiredSignatureError:
            return jsonify({"error": "Token has expired"}), 401
        except jwt.InvalidTokenError:
            return jsonify({"error": "Invalid token"}), 401

        return fn(*args, **kwargs)
    return wrapper

@app.post("/login")
def login():
    data = request.get_json(silent=True) or {}
    username = data.get("username", "")
    password = data.get("password", "")

    user = users.get(username)
    if not user or not check_password_hash(user["password_hash"], password):
        return jsonify({"error": "Invalid credentials"}), 401

    token = create_token(user["id"], user["username"])
    return jsonify({
        "access_token": token,
        "token_type": "Bearer",
        "expires_in_minutes": app.config["JWT_EXPIRATION_MINUTES"],
    })

@app.get("/profile")
@token_required
def profile():
    return jsonify({
        "message": "Authenticated request successful",
        "user": g.current_user,
    })

@app.post("/register")
def register():
    data = request.get_json(silent=True) or {}
    username = (data.get("username") or "").strip()
    password = data.get("password") or ""

    if not username or not password:
        return jsonify({"error": "Username and password are required"}), 400

    if username in users:
        return jsonify({"error": "User already exists"}), 409

    user_id = max((u["id"] for u in users.values()), default=0) + 1
    users[username] = {
        "id": user_id,
        "username": username,
        "password_hash": generate_password_hash(password),
    }

    return jsonify({"message": "User registered successfully"}), 201

@app.get("/")
def index():
    return jsonify({
        "message": "Flask JWT auth API",
        "endpoints": {
            "register": "POST /register",
            "login": "POST /login",
            "profile": "GET /profile",
        },
    })

if __name__ == "__main__":
    app.run(debug=True)